import{_ as s,o as a,c as i,a5 as t}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 PFC 输入电压前馈","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 PFC 输入电压前馈","tags":["power-electronics"],"status":"learning","summary":"功率因数校正（power factor correction / PFC）中的输入电压前馈（input-voltage feedforward）是把输入电压的均方根值（root mean square / RMS）提前放进功率命令到电流命令的换算里。"},"headers":[],"relativePath":"content/power/concepts/power-electronics/single-phase-pfc-voltage-feedforward.md","filePath":"content/power/concepts/power-electronics/single-phase-pfc-voltage-feedforward.md","lastUpdated":null}'),l={name:"content/power/concepts/power-electronics/single-phase-pfc-voltage-feedforward.md"};function n(p,e,o,d,r,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="概念-单相-pfc-输入电压前馈" tabindex="-1">概念：单相 PFC 输入电压前馈 <a class="header-anchor" href="#概念-单相-pfc-输入电压前馈" aria-label="Permalink to &quot;概念：单相 PFC 输入电压前馈&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）中的输入电压前馈（input-voltage feedforward）是把输入电压的均方根值（root mean square / RMS）提前放进功率命令到电流命令的换算里。</p><p>本节只讲一个概念：为什么常见的平均模型里会写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>G = Pcmd / Vrms^2</span></span>
<span class="line"><span>I_rms_ref = G * Vrms</span></span></code></pre></div><p>这里 <code>G</code> 是电导命令（conductance command / G），<code>Pcmd</code> 是输入功率命令，<code>Vrms</code> 是输入电压 RMS。</p><p>本节不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。维护本学习仓库时，不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）的 PFC 级要在输入电网电压变化时尽量稳定地从电网取功率。如果只固定电导命令，那么：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pin = G * Vrms^2</span></span></code></pre></div><p>当 <code>Vrms</code> 从 220 V 掉到 180 V，输入功率会明显下降；当 <code>Vrms</code> 升到 264 V，输入功率会明显上升。母线电压环最终能慢慢修正，但电网电压变化刚发生时会给母线带来扰动。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>PFC 把输入端“看起来”做成一个受控电阻或受控电导：电压越高，按比例吸取的电流越大。功率等于电压乘电流，所以如果 <code>G</code> 不变，功率会随 <code>Vrms^2</code> 变化。</p><p>输入电压前馈的直觉是：电压高时把电导命令压低，电压低时把电导命令抬高，让 <code>G * Vrms^2</code> 尽量保持等于功率命令。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>平均意义下，单相正弦输入可写成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>v(t) = Vpk * sin(theta)</span></span>
<span class="line"><span>i_ref(t) = G * v(t)</span></span>
<span class="line"><span>Pin_avg = Vrms * Irms = G * Vrms^2</span></span></code></pre></div><p>为了让平均输入功率接近 <code>Pcmd</code>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>G_ff = Pcmd / Vrms^2</span></span>
<span class="line"><span>Irms_ref = G_ff * Vrms = Pcmd / Vrms</span></span></code></pre></div><p>这不是完整的电压环，也不是完整的电流环。它只是把输入电压变化提前补偿掉，减轻后面比例积分控制器（proportional-integral controller / PI）的压力。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_feedforward.py</span></span></code></pre></div><p>对比一个仿真任务：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_feedforward.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rms</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">step </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">180</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_feedforward_180v.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_pfc_voltage_feedforward.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rms</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">step </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">264</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\pfc_feedforward_264v.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>观察：</p><ul><li>输入电压 RMS 从 220 V 跳到 180 V 后，固定电导的输入功率会低于命令值。</li><li>使用 <code>G = Pcmd / Vrms^2</code> 后，输入功率仍接近 <code>Pcmd</code>。</li><li>图中的参数框写明 <code>Vrms_initial</code>、<code>Vrms_step</code>、<code>Pcmd</code>、控制频率和仿真时长。</li><li>每条曲线都有图例，不需要猜哪条曲线代表什么。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>工程里通常不会把这个式子孤立地放着，而是放在 PFC 电压环输出到电流幅值之间：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pcmd or voltage_loop_output</span></span>
<span class="line"><span>  -&gt; input RMS measurement/filter</span></span>
<span class="line"><span>  -&gt; G = Pcmd / max(Vrms^2, lower_limit)</span></span>
<span class="line"><span>  -&gt; current reference amplitude</span></span>
<span class="line"><span>  -&gt; PWM current loop</span></span></code></pre></div><p>实现时要注意：</p><ul><li><code>Vrms</code> 需要滤波，不能直接使用噪声很大的瞬时采样值。</li><li>分母要加下限，避免低电压或采样异常时电流命令暴涨。</li><li>前馈只解决输入电压变化带来的功率换算问题，不能替代保护逻辑。</li><li>脉宽调制（pulse-width modulation / PWM）电流环仍然要负责实际电感电流跟踪。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：有了前馈就不需要母线电压环。<br> 正确理解：前馈只补偿输入电压变化；负载变化、损耗和模型误差仍需要电压环修正。</p></li><li><p>错误理解：前馈越快越好。<br> 正确理解：<code>Vrms</code> 估算太快会把采样噪声带进电流命令，通常要滤波和限幅。</p></li><li><p>错误理解：固定电流幅值比固定电导更稳。<br> 正确理解：固定电流幅值时 <code>Pin = Vrms * Irms</code>，仍会随输入电压变化。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释为什么固定 <code>G</code> 时 <code>Pin = G * Vrms^2</code>。</li><li>能解释为什么 <code>G = Pcmd / Vrms^2</code> 可以让输入功率更接近命令值。</li><li>能在仿真图中指出 <code>Vrms</code>、<code>Pin_fixed</code>、<code>Pin_ff</code>、<code>G_fixed</code>、<code>G_ff</code>。</li><li>能说清楚低电压时为什么电流 RMS 命令会上升。</li><li>能基于 <code>single_phase_pfc_voltage_feedforward.py</code> 的仿真图准备具体导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>220 V 跳到 180 V 后，固定 <code>G</code> 的输入功率为什么会下降？下降比例大约和哪个量有关？</li><li>220 V 跳到 264 V 后，前馈为什么要降低 <code>G</code>？</li><li>如果 <code>Vrms</code> 估算值带噪声，电流命令会出现什么现象？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_pfc_voltage_feedforward.py</code> 看到 220 V 跳到 180 V 时，固定 <code>G</code> 的输入功率明显下降。公司 PFC 控制里是否使用 <code>Vrms^2</code> 输入电压前馈？</li><li>图里 <code>G_ff</code> 在低电压时变大。实际固件会怎样限制低压时的最大电流命令？</li><li>如果 <code>Vrms</code> 估算来自半周或整周滤波，公司平台一般怎样平衡前馈响应速度和噪声？</li></ul>`,40)])])}const u=s(l,[["render",n]]);export{k as __pageData,u as default};
